<template>
  <v-container fluid fill-height align-start ma-0 pa-2>
    <v-row no-gutters>
      <i-page-title title="alarmManage" />
      <v-col cols="12" sm="12" lg="12" class="pa-2">
        <v-card color="card_bg">
          <v-card-text class="d-flex flex-column flex-md-row align-md-center">
            <span class="content--text pb-2 pb-md-0">{{ $t('period') }}</span>
            <!-- datePicker -->
            <i-date-time-picker class="ml-md-2"></i-date-time-picker>
            <v-btn class="hidden-sm-and-down ml-2 px-3" outlined color="primary" @click="getData()">{{ $t('inquery') }}</v-btn>
            <v-btn class="hidden-md-and-up mt-2" block outlined color="primary" @click="getData()">{{ $t('inquery') }}</v-btn>
          </v-card-text>
          <v-divider class="mx-2" />
          <v-card-text class="pa-0 alarm-col-height">
            <v-card class="card_bg fill-height">
              <v-card-text class="fill-height">
                <i-data-table
                  :headers="headers"
                  :items="desserts"
                  v-bind:disablePagination="false"
                  :searchUse="true"
                  :loading="loading"
                  loading-text="Loading..."
                />
              </v-card-text>
            </v-card>
          </v-card-text>
        </v-card>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
//TODO alarm manage 삭제 검토
import iDateTimePicker from '@/components/common/iDateTimePicker.vue'
import { getAlarmData } from '@/api/setting/alarmManage'
import iPageTitle from '@/components/common/iPageTitle.vue'
import iDataTable from '@/components/common/iDataTable.vue'

export default {
  name: 'AlarmManage',
  components: {
    'i-date-time-picker': iDateTimePicker,
    'i-page-title': iPageTitle,
    'i-data-table': iDataTable
  },
  data() {
    return {
      loading: false,
      headers: [
        {
          text: this.$i18n.t('no'),
          value: 'rownum',
          align: 'center'
        },
        {
          text: this.$i18n.t('deviceName'),
          value: 'deviceId',
          align: 'center'
        },
        {
          text: this.$i18n.t('voltage'),
          value: 'outputVoltage',
          align: 'center'
        },
        {
          text: this.$i18n.t('current'),
          value: 'outputCurrent',
          align: 'center'
        },
        {
          text: this.$i18n.t('gas'),
          value: 'gasFlow',
          align: 'center'
        },
        {
          text: this.$i18n.t('feeding'),
          value: 'feedingSpeed',
          align: 'center'
        }
      ],
      desserts: []
    }
  },
  methods: {
    getData() {
      this.loading = true
      getAlarmData().then(res => {
        this.desserts = res.list
        this.loading = false
      })
    }
  }
}
</script>
<style lang="scss" scoped>
$appBarHeight: 64px;
$cardTitleHeight: 48px;
$paddingHeight: 8px;

.alarm-col-height {
  height: 100vh;
  max-height: calc(100vh - (#{$appBarHeight} + (#{$cardTitleHeight} * 2) + (#{$paddingHeight} * 8)));
}
</style>
